//#region js/helpers.js
function reverseAudioBuffer(buffer, audioContext) {
	const reversedBuffer = audioContext.createBuffer(buffer.numberOfChannels, buffer.length, buffer.sampleRate);
	for (let channel = 0; channel < buffer.numberOfChannels; channel++) {
		const originalData = buffer.getChannelData(channel);
		const reversedData = reversedBuffer.getChannelData(channel);
		for (let i = 0; i < originalData.length; i++) reversedData[i] = originalData[originalData.length - 1 - i];
	}
	return reversedBuffer;
}
